"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[764],{7764:function(e,t,r){r.d(t,{JM:function(){return i},Vh:function(){return a},ch:function(){return d},tx:function(){return n},z2:function(){return l}});let i=[{name:"Nye konti",logic:"signup_date inden for sidste dag AND lifetime_downloads = 0",usedBy:"Flow 1"},{name:"Ikke aktiveret",logic:"kontoalder > 2 dage AND first_download_date er tom",usedBy:"Flow 1 recovery"},{name:"Trial — aktiv",logic:"account_type = trial AND trial_end_date i fremtiden",usedBy:"Flow 2A"},{name:"Trial — slutter",logic:"account_type = trial AND trial_end_date inden for 3 dage",usedBy:"Flow 2A"},{name:"Trial — udl\xf8bet",logic:"account_type = trial-expired AND trial_end_date sidste 14 dage",usedBy:"Flow 2A"},{name:"Heavy credit-k\xf8ber",logic:"account_type = credit_only AND downloads_last_30d ≥ 8",usedBy:"Flow 2B"},{name:"Lav credit-saldo",logic:"credit_balance ≤ 5 AND credit_balance > 0",usedBy:"Flow 2C"},{name:"Ingen credits",logic:"credit_balance = 0 AND last_credit_purchase_date er sat",usedBy:"Flow 2C"},{name:"Fornyelse n\xe6r",logic:"subscription_renewal_date inden for 30 dage (\xe5rlig) / 7 (m\xe5nedlig)",usedBy:"Flow 2D"},{name:"Betaling fejlet",logic:"payment_failed_flag = true",usedBy:"Flow 2D dunning"},{name:"Dvalende abonnent",logic:"account_type in (subscriber, hybrid) AND last_login_date > 30 dage",usedBy:"Flow 3A"},{name:"Churnet",logic:"account_type = churned OR subscription_canceled_date er sat",usedBy:"Flow 3B"},{name:"Inaktiv",logic:"ingen email-\xe5bning i 180 dage",usedBy:"Flow 3C sunset"},{name:"Efter asset-interesse",logic:"primary_asset_interest = photos | illustrations | video | icons | templates",usedBy:"Flow 4 personalisering"}],n=[{id:"flow-1",number:"1",title:"Onboarding & Aktivering",job:"Aktiv\xe9r",summary:"Bring hver ny konto til deres f\xf8rste meningsfulde download (aktivering) og s\xe5 fr\xf8et til kernevaner: s\xf8gning, Collections, DAM'et.",trigger:'account_created → kontakten kommer ind i segmentet "Nye konti".',audience:"account_type = trial OR free.",cadence:"6 emails over ~9 dage.",exit:"subscription_started → exit; ELLER trial_end_date inden for 7 dage → overdrag til Flow 2A; ELLER serien afsluttes.",delivery:"Marketing Automation (segment-entry). Email 2 og 6 sender kun hvis first_download_date er tom.",suppression:"Product onboarding.",primaryKpi:"Aktiveringsrate (f\xf8rste download)",benchmark:"35–50%",emails:[{id:"1.1",title:"Velkomst",trigger:"Straks ved account_created.",audience:"Alle nye konti.",subject:"Velkommen til Colourbox/Skyfish — lad os finde dit f\xf8rste perfekte asset",preheader:"Dit bibliotek af millioner af assets er klar. Her er den hurtigste vej ind.",body:'Hej {{first_name}}, velkommen ombord. Du har nu hele Colourbox/Skyfish-biblioteket lige ved h\xe5nden — fotos, illustrationer, video og mere, alt licenseret og klar til brug.\n\nHurtigste m\xe5de at se hvad Colourbox/Skyfish kan, er at lave \xe9n s\xf8gning p\xe5 noget du faktisk har brug for denne uge. Specifikke termer sl\xe5r brede — pr\xf8v "team meeting candid" frem for "business".',cta:"Start s\xf8gning"},{id:"1.2",title:"Aktiverings-nudge",trigger:"Dag 1 — kun hvis first_download_date er tom.",audience:"Nye konti, ikke aktiverede endnu.",subject:"Din f\xf8rste download — s\xe5dan g\xf8r du (det tager 20 sekunder)",preheader:"Find det, download det, brug det. Ingen attributionsb\xf8vl.",body:"Hej {{first_name}}, vi kan se du endnu ikke har hentet dit f\xf8rste asset — her er hele \xf8velsen: s\xf8g, klik p\xe5 et asset du kan lide, tryk Download. Licensen er inkluderet, s\xe5 du er klar til at bruge det i samme \xf8jeblik det lander.\n\nIkke sikker p\xe5 hvor du skal starte? Disse trending collections er et godt f\xf8rste stop.",cta:"Browse trending assets"},{id:"1.3",title:"Feature spotlight — Collections",trigger:"Dag 3.",audience:"Alle nye konti.",subject:"Tricket bureauer bruger s\xe5 de aldrig taber et asset igen",preheader:"Collections g\xf8r en rodet downloads-mappe til et organiseret bibliotek.",body:'Hej {{first_name}}, hvert asset du gemmer i en Collection forbliver organiseret, s\xf8gbart og delt — ikke mere graven gennem en downloads-mappe efter "det ene billede".\n\nStart \xe9n til dit aktuelle projekt. Det fremtidige dig vil takke dig.',cta:"Opret din f\xf8rste collection"},{id:"1.4",title:"Feature spotlight — DAM'et",trigger:"Dag 5.",audience:"Alle nye konti.",subject:"Stop med at emaile filer rundt",preheader:"Versionering, deling og brand-mapper — dine assets \xe9t sted.",body:"Hej {{first_name}}, Colourbox/Skyfish er ikke bare et stock-bibliotek — det er hvor dit teams assets bor. Upload jeres egne filer ved siden af licenserede, hold styr p\xe5 versioner, og del et link i stedet for en 40 MB vedh\xe6ftning.\n\n{{#if is_team_admin}}Inviter dit team s\xe5 alle arbejder fra samme kilde.{{else}}Sp\xf8rg din admin om team-mapper — eller udforsk hvad der allerede er der.{{/if}}",cta:"Udforsk dit asset-bibliotek"},{id:"1.5",title:"Social proof & use cases",trigger:"Dag 7.",audience:"Alle nye konti.",subject:"S\xe5dan f\xe5r teams som dit en uge tilbage hver m\xe5ned",preheader:"Rigtige workflows, fra f\xf8rste s\xf8gning til f\xe6rdig kampagne.",body:"Hej {{first_name}}, de kunder der f\xe5r mest ud af Colourbox/Skyfish, behandler det som trin \xe9t i hver kreativ opgave — moodboard i Collections, licens p\xe5 \xe9t klik, aflever med et delelink.\n\nSe hvordan tre forskellige teams g\xf8r det i praksis.",cta:"Se Colourbox/Skyfish i aktion"},{id:"1.6",title:"Aktiverings-recovery",trigger:"Dag 9 — kun hvis first_download_date stadig er tom.",audience:"Nye konti, aldrig aktiveret.",subject:"Kom du p\xe5 tv\xe6rs af noget?",preheader:"En hurtig h\xe5nd til at f\xe5 dig til din f\xf8rste download.",body:"Hej {{first_name}}, du tilmeldte dig men har ikke downloadet noget endnu — det er helt fint, men vi vil gerne vide om noget gik galt.\n\nSvar p\xe5 denne email og en rigtig person hj\xe6lper, eller spring direkte til et starter-pack vi har samlet til nye konti.",cta:"F\xe5 starter-pakken",notes:"Hvis stadig ikke aktiveret 3 dage efter denne email, exit til Flow 2A (hvis trial) eller Flow 4B nyhedsbrev-kadence (hvis free)."}]},{id:"flow-2",number:"2",title:"Trial & Abonnement-konvertering",job:"Konverter",summary:"Fire sub-flows oms\xe6tter intention til betaling: trials til abonnementer, hyppige credit-k\xf8bere til abonnenter, lave saldi til top-ups, og fornyelser til fastholdt oms\xe6tning — inklusive en dunning-sekvens.",trigger:"Flere — trial-start, credit-brug, fornyelse n\xe6r, betaling fejlet.",audience:"Trials, credit-k\xf8bere, abonnenter.",cadence:"18 emails fordelt p\xe5 4 sub-flows.",exit:"Per sub-flow — se nedenfor.",delivery:"Mix af Marketing Automation og event-triggerede API-sendninger.",suppression:"Billing & account, Offers & promotions.",primaryKpi:"Trial→betalt %, dunning recovery %",benchmark:"15–25% / 40–60%",subflows:[{id:"2A",title:"2A \xb7 Trial til betalt",description:"Antager en 14-dages trial. En brugs-bevidst nedt\xe6lling: vis folk hvad de allerede har gjort, s\xe5 hvad de ville miste. 3 emails i trial-perioden, 3 efter udl\xf8b.",emails:[{id:"2A.1",title:"Midt-trial v\xe6rdi-opsummering",trigger:"Dag 7 af trial.",audience:"Aktive trials.",subject:"Du har downloadet {{downloads_last_30d}} assets — her er hvad en plan l\xe5ser op",preheader:"Et hurtigt kig p\xe5 din trial indtil nu.",body:"Hej {{first_name}}, \xe9n uge inde i din trial og du har allerede trukket {{downloads_last_30d}} assets og startet {{saved_collections_count}} collection(s). Flot arbejde.\n\nP\xe5 en plan forts\xe6tter det bare — ubegr\xe6nsede downloads, hele biblioteket, og hver collection du har bygget bliver pr\xe6cis hvor den er. Her er hvordan planerne sammenlignes.",cta:"Se planer & priser"},{id:"2A.2",title:"Trial slutter — 3 dage tilbage",trigger:"3 dage f\xf8r trial_end_date.",audience:"Aktive trials.",subject:"3 dage tilbage — dine collections er ved at l\xe5ses",preheader:"Behold dit bibliotek, licenser og collections.",body:"Hej {{first_name}}, din trial slutter {{trial_end_date}}. N\xe5r den g\xf8r, er dine collections og download-historik gemt — men du skal have en plan for at forts\xe6tte med at downloade og holde nye licenser gyldige.\n\nV\xe6lg den plan der passer, og der er ingen afbrydelse.",cta:"V\xe6lg din plan"},{id:"2A.3",title:"Trial slutter — sidste dag",trigger:"1 dag f\xf8r trial_end_date.",audience:"Aktive trials.",subject:"Din trial slutter i morgen, {{first_name}}",preheader:"To minutter for at holde alt k\xf8rende.",body:"Dette er sidste reminder — din Colourbox/Skyfish-trial slutter i morgen. Alt du har sat op forbliver intakt hvis du v\xe6lger en plan i dag.\n\nIkke klar til et abonnement? En credit-pakke holder dig downloadende uden m\xe5nedlig forpligtelse.",cta:"Hold min konto aktiv",notes:"To CTA'er tilladt her — plan (prim\xe6r knap) og credit-pakke (sekund\xe6r tekst-link)."},{id:"2A.4",title:"Trial udl\xf8bet",trigger:"Dag +1 efter trial_end_date.",audience:"account_type = trial-expired.",subject:"Din trial er f\xe6rdig — dine collections er i sikkerhed (forel\xf8big)",preheader:"S\xe5dan samler du op hvor du slap.",body:"Hej {{first_name}}, din trial er slut og din konto er nu p\xe5 free-niveau. Dine {{saved_collections_count}} collection(s) og historik er her stadig — men downloading er pauset.\n\nTo veje tilbage: et abonnement til ubegr\xe6nset brug, eller en credit-pakke hvis du bare har brug for nogle f\xe5 assets.",cta:"Reaktiv\xe9r med en plan"},{id:"2A.5",title:"Post-trial incitament",trigger:"Dag +4 efter trial_end_date.",audience:"account_type = trial-expired, ikke konverteret.",subject:"Stadig i tvivl? Her er 20% rabat p\xe5 din f\xf8rste m\xe5ned",preheader:"Et lille skub for at g\xf8re det nemt.",body:"Hej {{first_name}}, intet pres — men hvis prisen var sten i skoen, s\xe5 her er 20% rabat p\xe5 din f\xf8rste m\xe5ned (eller f\xf8rste \xe5r hvis du g\xe5r \xe5rligt). Koden anvendes automatisk ved checkout.\n\nTilbuddet g\xe6lder i 7 dage.",cta:"Indl\xf8s 20% rabat"},{id:"2A.6",title:"Sidste post-trial",trigger:"Dag +10 efter trial_end_date.",audience:"account_type = trial-expired, ikke konverteret.",subject:"Vi holder din konto varm",preheader:"Ingen flere reminders — bare s\xe5 du ved hvor tingene st\xe5r.",body:"Hej {{first_name}}, dette er sidste gang du h\xf8rer fra os om din trial. Dine collections forbliver gemt, og du er velkommen tilbage n\xe5r som helst.\n\nVi skifter dig til vores lejlighedsvise nye-assets-email s\xe5 du kan se hvad der lander. En credit-pakke er altid den lav-forpligtelses vej tilbage.",cta:"Browse credit-pakker",notes:"Ved afsendelse, flyt kontakten ind i Flow 4B nyhedsbrev-kadence og exit 2A."}]},{id:"2B",title:"2B \xb7 Credit-k\xf8ber → abonnement upsell",description:"Hyppige credit-k\xf8bere efterlader penge p\xe5 bordet — og uds\xe6tter sig for friktion hver gang de rammer nul. Dette sub-flow g\xf8r regnestykket \xe5benlyst.",emails:[{id:"2B.1",title:"Omkostningssammenligning",trigger:"Ved segment-entry.",audience:"Heavy credit-k\xf8bere.",subject:"Du har brugt mere p\xe5 credits end en plan ville koste",preheader:"Regnestykket, til din fordel.",body:"Hej {{first_name}}, du har k\xf8bt {{credits_purchased_lifetime}} credits hos os — og i dit nuv\xe6rende tempo ville et abonnement allerede have kostet dig mindre og givet dig ubegr\xe6nsede downloads.\n\nHer er side-om-side for dit faktiske forbrug.",cta:"Se om en plan sparer dig penge"},{id:"2B.2",title:"Mere end pris",trigger:"Dag 4.",audience:"Heavy credit-k\xf8bere, ikke konverteret.",subject:"Det er ikke kun billigere — det er mindre friktion",preheader:"Ikke flere top-ups midt i projektet.",body:"Hej {{first_name}}, forbi prisen: en plan betyder aldrig at ramme nul midt i projektet, fuld adgang til premium collections, og DAM-v\xe6rkt\xf8jerne til at holde styr p\xe5 alt.\n\nDin credit-historik og collections f\xf8lger direkte med.",cta:"Skift til en plan"},{id:"2B.3",title:"Skift-incitament",trigger:"Dag 10.",audience:"Heavy credit-k\xf8bere, ikke konverteret.",subject:"Skift denne uge, f\xe5 din f\xf8rste m\xe5ned til halv pris",preheader:"En tak for at flytte op.",body:"Hej {{first_name}}, hvis et abonnement har v\xe6ret i tankerne, s\xe5 her er en grund til at g\xf8re det nu — 50% rabat p\xe5 din f\xf8rste m\xe5ned n\xe5r du skifter inden for de n\xe6ste 7 dage.\n\nUbrugte credits forbliver p\xe5 din konto som buffer.",cta:"Skift og spar 50%"}]},{id:"2C",title:"2C \xb7 Credit-genopfyldning",description:"Real-time og kort. Fjern friktion f\xf8r det afbryder et projekt — og diskret synligg\xf8r abonnementet hvor det ville v\xe6re billigere.",emails:[{id:"2C.1",title:"L\xf8ber lav",trigger:"Ved credit_balance ≤ 5 (og > 0).",audience:"Credit-k\xf8bere med lav saldo.",subject:"Du er nede p\xe5 {{credit_balance}} credits",preheader:"Fyld op f\xf8r dit n\xe6ste projekt g\xe5r i st\xe5.",body:"Hej {{first_name}}, heads up — du har {{credit_balance}} credits tilbage. At fylde op nu betyder ingen afbrydelse n\xe6ste gang du finder det perfekte asset.\n\nSt\xf8rre pakker har en bedre pris pr. credit, hvis du ved at mere arbejde er p\xe5 vej.",cta:"Fyld op med credits"},{id:"2C.2",title:"Ingen credits",trigger:"Ved credit_balance = 0.",audience:"Credit-k\xf8bere med nul saldo.",subject:"Du er l\xf8bet t\xf8r for credits — her er den 30-sekunders fix",preheader:"Plus: en plan giver m\xe5ske mere mening nu.",body:"Hej {{first_name}}, din saldo ramte lige nul. Hent en pakke og du downloader igen med det samme.\n\nK\xf8ber regelm\xe6ssigt pakker? Et abonnement er normalt billigere og l\xf8ber aldrig t\xf8r — v\xe6rd at kigge p\xe5.",cta:"K\xf8b en credit-pakke",notes:'Hvis kontakten ogs\xe5 matcher "Heavy credit-k\xf8ber", foretr\xe6k Flow 2B — frekvensloft forhindrer overlap.'}]},{id:"2D",title:"2D \xb7 Fornyelses-beskyttelse & failed-payment recovery",description:"To spor: fornyelses-sporet omformulerer regningen som en v\xe6rdi-opsummering; dunning-sporet recoverer fejlede betalinger over 10 dage f\xf8r en konto pauses. Dunning-emails er account-critical og bypasser marketing opt-out.",emails:[{id:"2D.1",title:"Fornyelses-varsel",trigger:"30 dage f\xf8r fornyelse (\xe5rlig) / 7 dage (m\xe5nedlig).",audience:"Abonnenter der n\xe6rmer sig fornyelse.",subject:"Dit \xe5r med Colourbox/Skyfish: {{lifetime_downloads}} downloads og t\xe6ller op",preheader:"Din plan fornyes {{subscription_renewal_date}}.",body:"Hej {{first_name}}, din plan fornyes {{subscription_renewal_date}} — intet at g\xf8re for dig, men her er hvad den har d\xe6kket: {{lifetime_downloads}} downloads, {{saved_collections_count}} collections, og en licens p\xe5 hver eneste.\n\nMeget mere lander i \xe5r ogs\xe5. Her er et glimt af hvad der kommer.",cta:"Se hvad der er nyt"},{id:"2D.2",title:"I-risiko fornyelses-reminder",trigger:"7 dage f\xf8r fornyelse — kun hvis downloads_last_30d er under t\xe6rskel.",audience:"I-risiko abonnenter n\xe6r fornyelse.",subject:"Din plan fornyes om 7 dage — lad os g\xf8re det v\xe6rd at have",preheader:"Et par ting du m\xe5ske har overset.",body:"Hej {{first_name}}, din fornyelse lander {{subscription_renewal_date}}. Vi har bem\xe6rket det er et stykke tid siden du har downloadet — her er nogle f\xe5 collections v\xe6rd at se inden.\n\nSp\xf8rgsm\xe5l om din plan? Svar bare.",cta:"Hop tilbage ind"},{id:"2D.3",title:"Fornyelsesbekr\xe6ftelse",trigger:"Ved subscription_renewed.",audience:"Fornyede abonnenter.",subject:"Du er klar til endnu en {{billing_cycle}}",preheader:"Tak for at blive hos Colourbox/Skyfish.",body:"Hej {{first_name}}, din plan blev lige fornyet — tak. Alt forts\xe6tter pr\xe6cis som det var, collections og det hele.\n\nHer er hvad der er nyt siden du startede.",cta:"Udforsk hvad der er nyt"},{id:"2D.4",title:"Betaling fejlet — Dag 0",trigger:"Straks ved payment_failed.",audience:"Abonnenter med fejlet betaling.",subject:"Vi kunne ikke gennemf\xf8re din betaling",preheader:"En hurtig kortopdatering holder alt k\xf8rende.",body:"Hej {{first_name}}, din seneste betaling gik ikke igennem — normalt et udl\xf8bet kort eller en midlertidig bank-blokering. Din konto er stadig aktiv for nu.\n\nAt opdatere dine detaljer tager omkring et minut.",cta:"Opdater betalingsoplysninger"},{id:"2D.5",title:"Betaling fejlet — Dag 3",trigger:"Dag 3 — hvis payment_failed_flag stadig true.",audience:"Abonnenter, betaling stadig fejlende.",subject:"Stadig brug for en h\xe5nd med din betaling?",preheader:"Vi pr\xf8ver automatisk igen s\xe5 snart dit kort er opdateret.",body:"Hej {{first_name}}, bare en reminder — vi har ikke kunnet gennemf\xf8re din betaling endnu. Opdater dit kort og vi pr\xf8ver igen med det samme, uden afbrydelse.",cta:"Fix min betaling"},{id:"2D.6",title:"Betaling fejlet — Dag 7",trigger:"Dag 7 — hvis payment_failed_flag stadig true.",audience:"Abonnenter, betaling stadig fejlende.",subject:"Din konto pauses om 3 dage",preheader:"Sidste chance for at holde tingene uafbrudte.",body:"Hej {{first_name}}, vi har pr\xf8vet et par gange nu. Hvis vi ikke kan gennemf\xf8re betalingen inden for de n\xe6ste 3 dage, vil din konto blive pauset — downloads slukket, collections gemt.\n\n\xc9n hurtig opdatering undg\xe5r alt sammen.",cta:"Opdater betaling nu"},{id:"2D.7",title:"Konto pauset — Dag 10",trigger:"Dag 10 — hvis payment_failed_flag stadig true.",audience:"Abonnenter, betaling ikke recovered.",subject:"Din konto er pauset — reaktiv\xe9r n\xe5r som helst",preheader:"Dine collections er i sikkerhed. Reaktivering tager \xe9t klik.",body:"Hej {{first_name}}, din konto er nu pauset fordi vi ikke kunne gennemf\xf8re betalingen. Intet er tabt — dine collections og historik er pr\xe6cis hvor du forlod dem.\n\nOpdater dit kort og du er tilbage med det samme.",cta:"Reaktiv\xe9r min konto"}]}]},{id:"flow-3",number:"3",title:"Re-engagement & Win-back",job:"Genaktiv\xe9r",summary:"Tre sub-flows fanger kunder p\xe5 tre forskellige afstande: den betalende abonnent der er blevet stille, kunden der er churnet, og kontakten der ikke \xe5bner noget l\xe6ngere.",trigger:"Dvale, opsigelse, eller 180 dage uden en \xe5bning.",audience:"Abonnenter, churnede, inaktive.",cadence:"8 emails fordelt p\xe5 3 sub-flows.",exit:"Login, gen-k\xf8b, eller enhver \xe5bning / klik.",delivery:"Marketing Automation + event-triggered API-sendning.",suppression:"New assets & inspiration, Offers & promotions.",primaryKpi:"Reaktiverings-rate",benchmark:"10–20% / 5–12%",subflows:[{id:"3A",title:"3A \xb7 Dvalende abonnent-redning",description:"Mest v\xe6rdifulde re-engagement-arbejde: en betalende-men-inaktiv abonnent er en opsigelse der venter p\xe5 at ske. Fang dem f\xf8r fornyelse.",emails:[{id:"3A.1",title:"Vi savner dig + hvad er nyt",trigger:"Ved indgang i Dvalende abonnent-segmentet (~30 dage inaktiv).",audience:"Dvalende abonnenter.",subject:"{{new_asset_count}} nye {{primary_asset_interest}}-assets siden du sidst var her",preheader:"Din plan har v\xe6ret i gang selv hvis du ikke har.",body:"Hej {{first_name}}, der er g\xe5et et par uger — og dit bibliotek er vokset. Der venter friske {{primary_asset_interest}}-assets der matcher hvad du typisk downloader.",cta:"Se hvad der er nyt"},{id:"3A.2",title:"F\xe5 din plan til at tjene sig selv hjem",trigger:"Dag 45 inaktiv.",audience:"Stadig-dvalende abonnenter.",subject:"Din plan inkluderer ubegr\xe6nsede downloads — lad os bruge dem",preheader:"Du betaler for det; her er hvordan du f\xe5r v\xe6rdien tilbage.",body:"Hej {{first_name}}, et hurtigt nudge: dit abonnement giver dig ubegr\xe6nsede downloads og fuld adgang til hver collection. Lige nu ligger det stille.\n\nHer er en kort liste til at g\xf8re dit n\xe6ste projekt hurtigere.",cta:"Browse kurerede picks"},{id:"3A.3",title:"Feedback-sp\xf8rgsm\xe5l",trigger:"Dag 60 inaktiv.",audience:"Stadig-dvalende abonnenter.",subject:"Virker Colourbox/Skyfish stadig for dig?",preheader:"\xc9t sp\xf8rgsm\xe5l — vi vil \xe6rligt vide det.",body:"Hej {{first_name}}, vi vil hellere h\xf8re det fra dig end g\xe6tte. B\xe6rer Colourbox/Skyfish stadig sin v\xe6gt? \xc9t klik nedenfor fort\xe6ller os hvor du er — og hvis noget er galt, hj\xe6lper vi personligt med at f\xe5 det l\xf8st.",cta:"Fort\xe6l os med \xe9t klik",notes:"Hvis stadig dvalende 14 dage efter denne email, flag kontoen for CS-outreach f\xf8r fornyelse."}]},{id:"3B",title:"3B \xb7 Bortfaldet / churnet win-back",description:"Et 45-dages vindue mens collections stadig er gemt og relationen stadig er varm. Start med hvad der er \xe6ndret, s\xe5 lav tilbuddet, s\xe5 sp\xf8rg hvorfor.",emails:[{id:"3B.1",title:"Hvad er \xe6ndret",trigger:"Dag 14 efter churn.",audience:"Nyligt churnede kontakter.",subject:"Vi har tilf\xf8jet en del siden du forlod os",preheader:"Ingen pitch endnu — bare hvad der er nyt.",body:"Hej {{first_name}}, siden du har v\xe6ret v\xe6k, er biblioteket vokset og vi har shippet et par ting kunder bad om. Ingen h\xe5rd salg her — vi t\xe6nkte bare du gerne ville se det.",cta:"Se hvad der er nyt"},{id:"3B.2",title:"Win-back tilbud",trigger:"Dag 30 efter churn.",audience:"Churnet, ikke tilbage endnu.",subject:"Kom tilbage med 30% rabat — eller tag bare en credit-pakke",preheader:"To nemme veje tilbage.",body:"Hej {{first_name}}, hvis du har overvejet at vende tilbage, s\xe5 her er en grund: 30% rabat p\xe5 din f\xf8rste m\xe5ned p\xe5 enhver plan. Dine gamle collections er stadig gemt og venter.\n\nIkke klar til at forpligte dig? En credit-pakke giver dig hvad du har brug for uden bindinger.",cta:"Reaktiv\xe9r med 30% rabat"},{id:"3B.3",title:"Sidste kald + feedback",trigger:"Dag 45 efter churn.",audience:"Churnet, ikke tilbage endnu.",subject:"F\xf8r vi siger farvel",preheader:"\xc9t sp\xf8rgsm\xe5l, og et sidste tilbud.",body:"Hej {{first_name}}, vi vil ikke blive ved med at maile — men f\xf8r vi g\xe5r stille, to ting: \xe9t hurtigt sp\xf8rgsm\xe5l om hvorfor du forlod os (det former oprigtigt hvad vi bygger), og 30%-tilbuddet er \xe5bent i 48 timer mere.",cta:"Fort\xe6l os hvorfor — og reaktiv\xe9r"}]},{id:"3C",title:"3C \xb7 Liste-hygiejne & sunset",description:"Ikke-glamour\xf8st, essentielt. At gen-bekr\xe6fte eller pensionere kontakter der aldrig \xe5bner beskytter sender-omd\xf8mmet hvert andet flow afh\xe6nger af.",emails:[{id:"3C.1",title:"Gen-tilladelse",trigger:"Ved indgang i Inaktiv-segmentet.",audience:"Inaktive kontakter.",subject:"Vil du stadig h\xf8re fra os?",preheader:"Vi maile kun videre hvis du siger ja.",body:"Hej {{first_name}}, vi har bem\xe6rket du ikke har \xe5bnet vores emails et stykke tid — intet problem overhovedet. Hvis du stadig gerne vil have Colourbox/Skyfish-opdateringer, s\xe5 klik nedenfor for at forblive abonneret.\n\nHvis ikke, beh\xf8ver du ikke g\xf8re noget — vi stopper, og din indbakke forbliver ren.",cta:"Ja, hold mig abonneret"},{id:"3C.2",title:"Sidste varsel",trigger:"Dag 10 — hvis ingen \xe5bning/klik p\xe5 Email 3C.1.",audience:"Stadig-inaktive kontakter.",subject:"Sidste email — medmindre du siger andet",preheader:"Vi rydder op. S\xe5dan bliver du p\xe5 listen.",body:"Hej {{first_name}}, dette er den sidste email vi sender medmindre du bekr\xe6fter du vil blive. \xc9t klik holder dig p\xe5 listen; stilhed flytter dig ud. Uanset hvad, ingen sure miner.",cta:"Hold mig p\xe5 listen",notes:"Ikke-svarere efter denne email: undertryk fra alle marketing-sendninger. Beskytter sender-omd\xf8mme."}]}]},{id:"flow-4",number:"4",title:"Adf\xe6rd & Promotional",job:"Konverter",summary:"Real-time reaktioner p\xe5 on-site adf\xe6rd, plus den planlagte promotional-kalender. H\xf8jeste oms\xe6tning pr. email fordi de n\xe5r folk i pr\xe6cis det \xf8jeblik intentionen er der.",trigger:"Real-time on-site adf\xe6rd + planlagte broadcasts.",audience:"Alle aktive konti.",cadence:"7 emails + s\xe6sonkalender.",exit:"Download / licens-event (eller n/a for l\xf8bende flows).",delivery:"Mest event-triggerede API-sendninger.",suppression:"New assets & inspiration, Offers & promotions.",primaryKpi:"Oms\xe6tning pr. email",benchmark:"10–20% (abandonment)",subflows:[{id:"4A",title:"4A \xb7 S\xf8gnings- & collection-abandonment",description:"Oms\xe6t aktiv intention — en s\xf8gning eller en kureret collection — til en download eller licens.",emails:[{id:"4A.1",title:"S\xf8gnings-abandonment",trigger:"48t efter search_performed uden download.",audience:"Aktive konti med en forladt s\xf8gning.",subject:'Leder du stadig efter "{{last_search_term}}"?',preheader:"Et par picks du m\xe5ske har overset.",body:'Hej {{first_name}}, du s\xf8gte efter "{{last_search_term}}" forleden men hentede ikke noget — det sker. Her er nogle st\xe6rke matches, plus et par friske vinkler p\xe5 samme id\xe9.',cta:"Se disse picks"},{id:"4A.2",title:"Collection-abandonment",trigger:"5 dage efter collection-aktivitet uden licens.",audience:"Aktive konti med en ulicenseret collection.",subject:"Din collection er klar n\xe5r du er",preheader:"{{saved_collections_count}} collection(s) venter p\xe5 dig.",body:"Hej {{first_name}}, du har kureret nogle gode assets ind i en collection men har ikke downloadet dem endnu. N\xe5r projektet er klar, er de \xe9t klik fra licens.",cta:"\xc5bn min collection"}]},{id:"4B",title:"4B \xb7 Nye-asset alerts",description:'"Home"-kadencen — en oprigtigt nyttig ugentlig email der holder Colourbox/Skyfish top-of-mind.',emails:[{id:"4B.1",title:"Ugentlige nye assets",trigger:"Ugentligt, fast dag/tid pr. lokalitet.",audience:"Marketing-tilladte kontakter, efter asset-interesse.",subject:"Denne uge i {{primary_asset_interest}}: {{new_asset_count}} nye picks",preheader:"Friskt i dit bibliotek — kureret til hvad du downloader.",body:"Hej {{first_name}}, her er hvad der er nyt i {{primary_asset_interest}} denne uge — h\xe5ndplukket til at matche hvad du faktisk bruger.\n\n{{#each new_assets}} {{this.title}} {{/each}}",cta:"Browse denne uges nye assets"}]},{id:"4C",title:"4C \xb7 Browse-abandonment",description:"Recov\xe9r h\xf8j-intention browsers der s\xe5 men ikke downloadede.",emails:[{id:"4C.1",title:"Browse-abandonment",trigger:"72t efter asset-detalje views uden download.",audience:"Aktive konti med en forladt browse.",subject:"Det asset du kiggede p\xe5 — plus 5 lignende",preheader:"Samler op hvor du slap.",body:"Hej {{first_name}}, du tog et n\xe6rt kig p\xe5 nogle f\xe5 assets men downloadede ikke — her er det du brugte l\xe6ngst tid p\xe5, plus fem t\xe6t-matchende i tilf\xe6lde af at det ikke var helt rigtigt.",cta:"Se disse assets"}]},{id:"4D",title:"4D \xb7 Post-download cross-sell",description:"\xd8g assets pr. session og forst\xe6rk download-vanen.",emails:[{id:"4D.1",title:"Post-download cross-sell",trigger:"Et par timer efter en download / licens-event.",audience:"Alle aktive konti.",subject:"Godt valg — her er hvad der passer til",preheader:"Assets der fungerer sammen med din seneste download.",body:"Hej {{first_name}}, godt valg p\xe5 din seneste download. Projekter har sj\xe6ldent kun brug for \xe9t asset, s\xe5 her er et s\xe6t der passer naturligt sammen — samme stil, samme shoot, eller en matchende serie.",cta:"Se matchende assets",notes:"Branch p\xe5 account_type: for credit-k\xf8bere, tilf\xf8j en bl\xf8d linje om bulk-pakker; for abonnenter, nudge Collections."}]},{id:"4F",title:"4F \xb7 Milestone-fejring",description:"Forst\xe6rk loyalitet ved naturlige h\xf8jdepunkter og \xe5bn en henvisnings-anmodning.",emails:[{id:"4F.1",title:"Milestone-fejring",trigger:"Ved milestone_reached (lifetime_downloads krydser 50 / 100 / 500).",audience:"Konti der krydser en download-milestone.",subject:"Du har downloadet {{lifetime_downloads}} assets med Colourbox/Skyfish",preheader:"En lille tak for et stort tal.",body:"Hej {{first_name}}, du krydsede lige {{lifetime_downloads}} downloads — det er et seri\xf8st stykke arbejde. Tak for at bygge det med os.\n\nHer er en lille ting: bonus-credits p\xe5 din konto. Og hvis du kender nogen der vil elske Colourbox/Skyfish, er der en henvisnings-bonus nedenfor til jer begge.",cta:"Del Colourbox/Skyfish, f\xe5 credits"}]},{id:"4G",title:"4G \xb7 Henvisning",description:"Forvandl glade power users til en anskaffelses-kanal.",emails:[{id:"4G.1",title:"Henvisnings-invitation",trigger:"Ved h\xf8j-engagement segment-entry, eller post-milestone.",audience:"Engagerede power users.",subject:"Giv en ven credits, f\xe5 credits selv",preheader:"Dit henvisnings-link, klar til at dele.",body:"Hej {{first_name}}, du f\xe5r tydeligvis meget ud af Colourbox/Skyfish — s\xe5 her er aftalen: del dit link, din ven f\xe5r bonus-credits ved signup, og du f\xe5r det samme n\xe5r de g\xf8r.\n\nIngen gr\xe6nse for hvor mange venner du inviterer. Dit link er nedenfor.",cta:"Hent mit henvisnings-link"}]}]}],d=[{name:"Product onboarding",contents:"Flow 1 — velkomst- og aktiverings-emails.",default:"Opt-in"},{name:"New assets & inspiration",contents:"Flow 4B nyhedsbrev, abandonment, cross-sell, milestones.",default:"Opt-in"},{name:"Offers & promotions",contents:"Incitamenter, win-back tilbud, henvisning, upsell.",default:"Opt-in"},{name:"Billing & account",contents:"Trial-udl\xf8b, dunning, fornyelse, credit-saldo. Account-critical.",default:"Altid p\xe5"}];function a(e){var t;return e.emails?e.emails:(null!==(t=e.subflows)&&void 0!==t?t:[]).flatMap(e=>e.emails.map(t=>({...t,subflowTitle:e.title})))}function l(e){for(let t of n){let r=a(t).find(t=>t.id===e);if(r)return{flow:t,email:r,subflowTitle:r.subflowTitle}}return null}}}]);